listitem.para:
event_nats — publishes &osips;
events and script payloads to NATS subjects,
optionally via JetStream async publish.

cachedb_nats — exposes NATS
Key-Value buckets through the &osips;
cachedb interface.

you need durable consumers with bounded
redelivery or replay semantics
(deliver_policy = by_start_seq);

you need synchronous request/reply with NATS as
a transport (nats_request)
from a non-request route;

example.programlisting:
modparam("nats_consumer", "fetch_batch", 32)

# Per-handle override: throughput-bound durable wants 256 per Fetch
# with a 4x ring and a >= ring max_ack_pending.  Empirical
# ~89 000 msgs/sec on loopback at this configuration.
nats_consumer_bind("id=ingest;stream=EVENTS;durable=ingest;
  fetch_batch=256;ring_capacity=1024;max_ack_pending=4096");

modparam("nats_consumer", "fetch_timeout_ms", 1000)

# RPC responder: stays responsive at shutdown by polling more often.
nats_consumer_bind("id=rpc;stream=API;durable=rpc;
  fetch_batch=4;fetch_timeout_ms=100");

route[PROCESS] {
    async(nats_fetch("orders", 5000), ON_MSG);
}

route[ON_MSG] {
    if ($retcode == 1) {
        xlog("L_INFO", "got $nats_subject: $nats_data\n");
        nats_ack();
    } else {
        xlog("L_WARN", "no message, rc=$retcode\n");
    }
}

timer_route[drain, 1] {
    $var(b) = 0;
    while ($var(b) < 5000) {
        nats_fetch_batch("jobs", "count=10;expires_ms=100");
        $var(rc) = $retcode;
        if ($var(rc) <= 0) { break; }
        $var(i) = 0;
        while ($var(i) < $var(rc)) {
            nats_batch_select($var(i));
            nats_ack();
            $var(i) = $var(i) + 1;
        }
        $var(b) = $var(b) + 1;
    }
}

startup_route {
    nats_consumer_bind(
        "id=jobs;stream=WORK;durable=jobs_worker;"
        "filter=work.jobs;ack_wait=30s;max_deliver=5");
}

timer_route[drain, 1] {
    while (nats_fetch("jobs", 250) > 0) {
        xlog("L_INFO", "job $nats_seq: $nats_data\n");
        nats_ack_next();
    }
}

startup_route {
    nats_consumer_bind(
        "id=dlq;stream=_SYS_JS;ephemeral=1;"
        "filter=$JS.EVENT.ADVISORY.MAX_DELIVERIES.>;"
        "inactive_threshold=5m");
}

timer_route[check_dlq, 5] {
    while (nats_fetch("dlq", 100) > 0) {
        xlog("L_ALERT", "dead letter: $nats_subject $nats_data\n");
        nats_ack();
    }
}

startup_route {
    nats_consumer_bind(
        "id=rpc_srv;stream=RPC;durable=srv;"
        "filter=rpc.call;ack_wait=5s");
}

timer_route[rpc_srv, 1] {
    while (nats_fetch("rpc_srv", 100) > 0) {
        nats_hdr_set("X-Trace-Id", "$nats_hdr(X-Trace-Id)");
        if (nats_reply("echo: $nats_data"))
            nats_ack();
        else
            nats_nak();
    }
}

timer_route[rpc_cli, 5] {
    if (nats_request("rpc.call", "ping", 2000))
        xlog("L_INFO", "reply: $nats_data\n");
}
